codeExamples.code:
class Tarea:
    def __init__(self, titulo):
        self.titulo = titulo
        self.completada = False

    def __str__(self):
        estado = '✔' if self.completada else '✘'
        return f'{self.titulo} - {estado}'

# Lista de tareas
tareas = []

def agregar_tarea(titulo):
    tareas.append(Tarea(titulo))

def mostrar_tareas():
    for t in tareas:
        print(t)

def guardar_tareas():
    with open('tareas.txt', 'w') as f:
        for t in tareas:
            f.write(f'{t.titulo}|{t.completada}\n')

agregar_tarea('Aprender Python')
agregar_tarea('Crear proyecto')
mostrar_tareas()
guardar_tareas()
